window.PACTO.acts["dir-2004-38"]={"label": "DIRETTIVA 2004/38/CE DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Dir. 38/2004", "file": "ext-dir-2004-38.html", "external": true, "version": "consolidato 2011-06-16", "eurlex": "https://eur-lex.europa.eu/eli/dir/2004/38/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Oggetto", "anchor": "art_1", "frags": [[null, "<p class=\"norm\">La presente direttiva determina:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>le modalità d'esercizio del diritto di libera circolazione e soggiorno nel territorio degli Stati membri da parte dei cittadini dell'Unione e dei loro familiari;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>il diritto di soggiorno permanente nel territorio degli Stati membri dei cittadini dell'Unione e dei loro familiari;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>le limitazioni dei suddetti diritti per motivi di ordine pubblico, di pubblica sicurezza o di sanità pubblica.</p>\n</div>"]]}, "2": {"label": "Articolo 2", "heading": "Definizioni", "anchor": "art_2", "frags": [[null, "<p class=\"norm\">Ai fini della presente direttiva, si intende per:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">1)<span style=\"word-spacing: 15pt\"> </span>«cittadino dell'Unione»: qualsiasi persona avente la cittadinanza di uno Stato membro;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">2)<span style=\"word-spacing: 15pt\"> </span>«familiare»:</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>il coniuge;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>il partner che abbia contratto con il cittadino dell'Unione un'unione registrata sulla base della legislazione di uno Stato membro, qualora la legislazione dello Stato membro ospitante equipari l'unione registrata al matrimonio e nel rispetto delle condizioni previste dalla pertinente legislazione dello Stato membro ospitante;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>i discendenti diretti di età inferiore a 21 anni o a carico e quelli del coniuge o partner di cui alla lettera b);</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>gli ascendenti diretti a carico e quelli del coniuge o partner di cui alla lettera b);</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">3)<span style=\"word-spacing: 15pt\"> </span>«Stato membro ospitante»: lo Stato membro nel quale il cittadino dell'Unione si reca al fine di esercitare il diritto di libera circolazione o di soggiorno.</p>\n</div>"]]}, "3": {"label": "Articolo 3", "heading": "Aventi diritto", "anchor": "art_3", "frags": [[null, "<p class=\"norm\">1.  La presente direttiva si applica a qualsiasi cittadino dell'Unione che si rechi o soggiorni in uno Stato membro diverso da quello di cui ha la cittadinanza, nonché ai suoi familiari ai sensi dell'articolo 2, punto 2, che accompagnino o raggiungano il cittadino medesimo.</p>"], [null, "<p class=\"norm\">2.  Senza pregiudizio del diritto personale di libera circolazione e di soggiorno dell'interessato lo Stato membro ospitante, conformemente alla sua legislazione nazionale, agevola l'ingresso e il soggiorno delle seguenti persone:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>ogni altro familiare, qualunque sia la sua cittadinanza, non definito all'articolo 2, punto 2, se è a carico o convive, nel paese di provenienza, con il cittadino dell'Unione titolare del diritto di soggiorno a titolo principale o se gravi motivi di salute impongono che il cittadino dell'Unione lo assista personalmente;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>il partner con cui il cittadino dell'Unione abbia una relazione stabile debitamente attestata.</p>\n</div>"], [null, "<p class=\"norm\">Lo Stato membro ospitante effettua un esame approfondito della situazione personale e giustifica l'eventuale rifiuto del loro ingresso o soggiorno.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "4": {"label": "Articolo 4", "heading": "Diritto di uscita", "anchor": "art_4", "frags": [[null, "<p class=\"norm\">1.  Senza pregiudizio delle disposizioni applicabili ai controlli dei documenti di viaggio alle frontiere nazionali, ogni cittadino dell'Unione munito di una carta d'identità o di un passaporto in corso di validità e i suoi familiari non aventi la cittadinanza di uno Stato membro e muniti di passaporto in corso di validità hanno il diritto di lasciare il territorio di uno Stato membro per recarsi in un altro Stato membro</p>"], [null, "<p class=\"norm\">2.  Nessun visto di uscita né alcuna formalità equivalente possono essere prescritti alle persone di cui al paragrafo 1.</p>"], [null, "<p class=\"norm\">3.  Gli Stati membri rilasciano o rinnovano ai loro cittadini, ai sensi della legislazione nazionale, una carta d'identità o un passaporto dai quali risulti la loro cittadinanza.</p>"], [null, "<p class=\"norm\">4.  Il passaporto deve essere valido almeno per tutti gli Stati membri e per i paesi di transito diretto tra gli stessi. Qualora la legislazione di uno Stato membro non preveda il rilascio di una carta d'identità, il periodo di validità del passaporto, al momento del rilascio o del rinnovo, non può essere inferiore a cinque anni.</p>"]]}, "5": {"label": "Articolo 5", "heading": "Diritto d'ingresso", "anchor": "art_5", "frags": [[null, "<p class=\"norm\">1.  Senza pregiudizio delle disposizioni applicabili ai controlli dei documenti di viaggio alle frontiere nazionali, gli Stati membri ammettono nel loro territorio il cittadino dell'Unione munito di una carta d'identità o di un passaporto in corso di validità, nonché i suoi familiari non aventi la cittadinanza di uno Stato membro, muniti di valido passaporto.</p>"], [null, "<p class=\"norm\">Nessun visto d'ingresso né alcuna formalità equivalente possono essere prescritti al cittadino dell'Unione.</p>"], [null, "<p class=\"norm\">2.  I familiari non aventi la cittadinanza di uno Stato membro sono soltanto assoggettati all'obbligo del visto d'ingresso, conformemente al regolamento (CE) n. 539/2001 o, se del caso, alla legislazione nazionale. Ai fini della presente direttiva il possesso della carta di soggiorno di cui all'articolo 10, in corso di validità, esonera detti familiari dal requisito di ottenere tale visto.</p>"], [null, "<p class=\"norm\">Gli Stati membri concedono a dette persone ogni agevolazione affinché ottengano i visti necessari. Tali visti sono rilasciati il più presto possibile in base a una procedura accelerata e sono gratuiti.</p>"], [null, "<p class=\"norm\">3.  Lo Stato membro ospitante non appone timbri di ingresso o di uscita nel passaporto del familiare non avente la cittadinanza di uno Stato membro, qualora questi esibisca la carta di soggiorno di cui all'articolo 10.</p>"], [null, "<p class=\"norm\">4.  Qualora il cittadino dell'Unione o il suo familiare non avente la cittadinanza di uno Stato membro sia sprovvisto dei documenti di viaggio o, eventualmente, dei visti necessari, lo Stato membro interessato concede, prima di procedere al respingimento, ogni possibile agevolazione affinché possa ottenere o far pervenire entro un periodo di tempo ragionevole i documenti necessari, oppure possa dimostrare o attestare con altri mezzi la qualifica di titolare del diritto di libera circolazione.</p>"], [null, "<p class=\"norm\">5.  Lo Stato membro può prescrivere all'interessato di dichiarare la propria presenza nel territorio nazionale entro un termine ragionevole e non discriminatorio. L'inosservanza di tale obbligo può comportare sanzioni proporzionate e non discriminatorie.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "6": {"label": "Articolo 6", "heading": "Diritto di soggiorno sino a tre mesi", "anchor": "art_6", "frags": [[null, "<p class=\"norm\">1.  I cittadini dell'Unione hanno il diritto di soggiornare nel territorio di un altro Stato membro per un periodo non superiore a tre mesi senza alcuna condizione o formalità, salvo il possesso di una carta d'identità o di un passaporto in corso di validità.</p>"], [null, "<p class=\"norm\">2.  Le disposizioni del paragrafo 1 si applicano anche ai familiari in possesso di un passaporto in corso di validità non aventi la cittadinanza di uno Stato membro che accompagnino o raggiungano il cittadino dell'Unione.</p>"]]}, "7": {"label": "Articolo 7", "heading": "Diritto di soggiorno per un periodo superiore a tre mesi", "anchor": "art_7", "frags": [[null, "<p class=\"norm\">1.  Ciascun cittadino dell'Unione ha il diritto di soggiornare per un periodo superiore a tre mesi nel territorio di un altro Stato membro, a condizione:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>di essere lavoratore subordinato o autonomo nello Stato membro ospitante; o</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>di disporre, per se stesso e per i propri familiari, di risorse economiche sufficienti, affinché non divenga un onere a carico dell'assistenza sociale dello Stato membro ospitante durante il periodo di soggiorno, e di un'assicurazione malattia che copra tutti i rischi nello Stato membro ospitante; o</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"normal\">c)</p>\n<span style=\"word-spacing: 15pt\"> </span>\n<div style=\"margin-left: 12pt; text-indent: -12pt; \">\n<p class=\"norm\">—<span style=\"word-spacing: 0\"> </span>di essere iscritto presso un istituto pubblico o privato, riconosciuto o finanziato dallo Stato membro ospitante in base alla sua legislazione o prassi amministrativa, per seguirvi a titolo principale un corso di studi inclusa una formazione professionale,</p>\n</div>\n<div style=\"margin-left: 12pt; text-indent: -12pt; \">\n<p class=\"norm\">—<span style=\"word-spacing: 0\"> </span>di disporre di un'assicurazione malattia che copre tutti i rischi nello Stato membro ospitante e di assicurare all'autorità nazionale competente, con una dichiarazione o con altro mezzo di sua scelta equivalente, di disporre, per se stesso e per i propri familiari, di risorse economiche sufficienti, affinché non divenga un onere a carico dell'assistenza sociale dello Stato membro ospitante durante il suo periodo di soggiorno; o</p>\n</div>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>di essere un familiare che accompagna o raggiunge un cittadino dell'Unione rispondente alle condizioni di cui alle lettere a), b) o c).</p>\n</div>"], [null, "<p class=\"norm\">2.  Il diritto di soggiorno di cui al paragrafo 1 è esteso ai familiari non aventi la cittadinanza di uno Stato membro quando accompagnino o raggiungano nello Stato membro ospitante il cittadino dell'Unione, purché questi risponda alla condizioni di cui al paragrafo 1, lettere a), b) o c).</p>"], [null, "<p class=\"norm\">3.  Ai sensi del paragrafo 1, lettera a), il cittadino dell'Unione che abbia cessato di essere un lavoratore subordinato o autonomo conserva la qualità di lavoratore subordinato o autonomo nei seguenti casi:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>l'interessato è temporaneamente inabile al lavoro a seguito di una malattia o di un infortunio;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>l'interessato, trovandosi in stato di disoccupazione involontaria debitamente comprovata dopo aver esercitato un'attività per oltre un anno, si è registrato presso l'ufficio di collocamento competente al fine di trovare un lavoro;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>l'interessato, trovandosi in stato di disoccupazione involontaria debitamente comprovata al termine di un contratto di lavoro di durata determinata inferiore ad un anno o venutosi a trovare in tale stato durante i primi dodici mesi, si è registrato presso l'ufficio di collocamento competente al fine di trovare un lavoro. In tal caso, l'interessato conserva la qualità di lavoratore subordinato per un periodo che non può essere inferiore a sei mesi;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>l'interessato segue un corso di formazione professionale. Salvo il caso di disoccupazione involontaria, la conservazione della qualità di lavoratore subordinato presuppone che esista un collegamento tra l'attività professionale precedentemente svolta e il corso di formazione seguito.</p>\n</div>"], [null, "<p class=\"norm\">4.  In deroga al paragrafo 1, lettera d) e al paragrafo 2, soltanto il coniuge, il partner che abbia contratto un'unione registrata prevista all'articolo 2, punto 2, lettera b) e i figli a carico godono del diritto di soggiorno in qualità di familiari di un cittadino dell'Unione che soddisfa le condizioni di cui al paragrafo 1, lettera c). L'articolo 3, paragrafo 2, si applica ai suoi ascendenti diretti e a quelli del coniuge o partner registrato.</p>"]]}, "8": {"label": "Articolo 8", "heading": "Formalità amministrative per i cittadini dell'Unione", "anchor": "art_8", "frags": [[null, "<p class=\"norm\">1.  Senza pregiudizio dell'articolo 5, paragrafo 5, per soggiorni di durata superiore a tre mesi lo Stato membro ospitante può richiedere ai cittadini dell'Unione l'iscrizione presso le autorità competenti.</p>"], [null, "<p class=\"norm\">2.  Il termine fissato per l'iscrizione non può essere inferiore a tre mesi dall'ingresso. Un attestato d'iscrizione è rilasciato immediatamente. Esso contiene l'indicazione precisa del nome e del domicilio della persona iscritta e la data dell'avvenuta iscrizione. L'inadempimento dell'obbligo di iscrizione rende l'interessato passibile di sanzioni proporzionate e non discriminatorie.</p>"], [null, "<p class=\"norm\">3.  Per il rilascio dell'attestato d'iscrizione, gli Stati membri possono unicamente prescrivere al</p>"], [null, "<div style=\"margin-left: 12pt; text-indent: -12pt; \">\n<p class=\"norm\">—<span style=\"word-spacing: 0\"> </span>cittadino dell'Unione cui si applica l'articolo 7, paragrafo 1, lettera a), di esibire una carta d'identità o un passaporto in corso di validità, una conferma di assunzione del datore di lavoro o un certificato di lavoro o una prova dell'attività autonoma esercitata,</p>\n</div>"], [null, "<div style=\"margin-left: 12pt; text-indent: -12pt; \">\n<p class=\"norm\">—<span style=\"word-spacing: 0\"> </span>cittadino dell'Unione cui si applica l'articolo 7, paragrafo 1, lettera b), di esibire una carta d'identità o un passaporto in corso di validità e di fornire la prova che le condizioni previste da tale norma sono soddisfatte,</p>\n</div>"], [null, "<div style=\"margin-left: 12pt; text-indent: -12pt; \">\n<p class=\"norm\">—<span style=\"word-spacing: 0\"> </span>cittadino dell'Unione cui si applica l'articolo 7, paragrafo 1, lettera c), di esibire una carta d'identità o un passaporto in corso di validità, di fornire la prova di essere iscritto presso un istituto riconosciuto e di disporre di un'assicurazione malattia che copre tutti i rischi e di esibire la dichiarazione o altro mezzo equivalente di cui all'articolo 7, paragrafo 1, lettera c). Gli Stati membri non possono esigere che detta dichiarazione indichi un importo specifico delle risorse.</p>\n</div>"], [null, "<p class=\"norm\">4.  Gli Stati membri si astengono dal fissare l'importo preciso delle risorse che considerano sufficienti, ma devono tener conto della situazione personale dell'interessato. In ogni caso, tale importo non può essere superiore al livello delle risorse al di sotto del quale i cittadini dello Stato membro ospitante beneficiano di prestazioni di assistenza sociale o, qualora non possa trovare applicazione tale criterio, alla pensione minima sociale erogata dallo Stato membro ospitante.</p>"], [null, "<p class=\"norm\">5.  Ai fini del rilascio dell'attestato d'iscrizione ai familiari del cittadino dell'Unione che siano essi stessi cittadini dell'Unione gli Stati membri possono prescrivere di presentare i seguenti documenti:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>carta d'identità o passaporto in corso di validità;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>un documento che attesti la qualità di familiare o l'esistenza di un'unione registrata;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>se opportuno, l'attestato d'iscrizione del cittadino dell'Unione che gli interessati accompagnano o raggiungono;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>nei casi di cui all'articolo 2, punto 2, lettere c) e d), la prova documentale che le condizioni di cui a tale disposizione sono soddisfatti;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>nei casi di cui all'articolo 3, paragrafo 2, lettera a), un documento rilasciato dall'autorità competente del paese di origine o di provenienza attestante che gli interessati sono a carico del cittadino dell'Unione o sono membri del nucleo familiare di quest'ultimo, o la prova che gravi motivi di salute del familiare impongono la prestazione di un'assistenza personale da parte del cittadino dell'Unione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">f)<span style=\"word-spacing: 17pt\"> </span>nei casi di cui all'articolo 3, paragrafo 2, lettera c), la prova di una relazione stabile con il cittadino dell'Unione.</p>\n</div>"]]}, "9": {"label": "Articolo 9", "heading": "Formalità amministrative per i familiari non aventi la cittadinanza di uno Stato membro", "anchor": "art_9", "frags": [[null, "<p class=\"norm\">1.  Quando la durata del soggiorno previsto è superiore a tre mesi, gli Stati membri rilasciano una carta di soggiorno ai familiari del cittadino dell'Unione non aventi la cittadinanza di uno Stato membro.</p>"], [null, "<p class=\"norm\">2.  Il termine entro il quale deve essere presentata la domanda per il rilascio della carta di soggiorno non può essere inferiore a tre mesi dall'arrivo.</p>"], [null, "<p class=\"norm\">3.  L'inadempimento dell'obbligo di richiedere la carta di soggiorno rende l'interessato passibile di sanzioni proporzionate e non discriminatorie.</p>"]]}, "10": {"label": "Articolo 10", "heading": "Rilascio della carta di soggiorno", "anchor": "art_10", "frags": [[null, "<p class=\"norm\">1.  Il diritto di soggiorno dei familiari del cittadino dell'Unione non aventi la cittadinanza di uno Stato membro è comprovato dal rilascio di un documento denominato «carta di soggiorno di familiare di un cittadino dell'Unione», che deve avvenire non oltre i sei mesi successivi alla presentazione della domanda. Una ricevuta della domanda di una carta di soggiorno è rilasciata immediatamente.</p>"], [null, "<p class=\"norm\">2.  Ai fini del rilascio della carta di soggiorno, gli Stati membri possono prescrivere la presentazione dei seguenti documenti:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>un passaporto in corso di validità;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>un documento che attesti la qualità di familiare o l'esistenza di un'unione registrata;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>l'attestato d'iscrizione o, in mancanza di un sistema di iscrizione, qualsiasi prova del soggiorno nello Stato membro ospitante del cittadino dell'Unione che gli interessati accompagnano o raggiungono;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>nei casi di cui all'articolo 2, punto 2, lettere c) e d), la prova documentale che le condizioni di cui a tale disposizione sono soddisfatti;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>nei casi di cui all'articolo 3, paragrafo 2, lettera a), un documento rilasciato dall'autorità competente del paese di origine o di provenienza attestante che gli interessati sono a carico del cittadino dell'Unione o membri del nucleo familiare di quest'ultimo, prova che gravi motivi di salute del familiare impongono la prestazione di un'assistenza personale da parte del cittadino dell'Unione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">f)<span style=\"word-spacing: 17pt\"> </span>nei casi di cui all'articolo 3, paragrafo 2, lettera c), la prova di una relazione stabile con il cittadino dell'Unione.</p>\n</div>"]]}, "11": {"label": "Articolo 11", "heading": "Validità della carta di soggiorno", "anchor": "art_11", "frags": [[null, "<p class=\"norm\">1.  La carta di soggiorno di cui all'articolo 10, paragrafo 1, ha un periodo di validità di cinque anni dalla data del rilascio o è valida per il periodo di soggiorno previsto del cittadino dell'Unione se tale periodo è inferiore a cinque anni.</p>"], [null, "<p class=\"norm\">2.  La validità della carta di soggiorno non è pregiudicata da assenze temporanee non superiori a sei mesi l'anno, né da assenze di durata superiore per l'assolvimento di obblighi militari, né da un'assenza di dodici mesi consecutivi al massimo dovuta a motivi rilevanti quali gravidanza e maternità, malattia grave, studi o formazione professionale o distacco per motivi di lavoro in un altro Stato membro o in un paese terzo.</p>"]]}, "12": {"label": "Articolo 12", "heading": "Conservazione del diritto di soggiorno dei familiari in caso di decesso o di partenza del cittadino dell'Unione", "anchor": "art_12", "frags": [[null, "<p class=\"norm\">1.  Senza pregiudizio delle disposizioni del secondo comma, il decesso del cittadino dell'Unione o la sua partenza dal territorio dello Stato membro ospitante non incidono sul diritto di soggiorno dei suoi familiari aventi la cittadinanza di uno Stato membro.</p>"], [null, "<p class=\"norm\">Prima dell'acquisizione del diritto di soggiorno permanente, le persone interessate devono soddisfare personalmente le condizioni previste all'articolo 7, paragrafo 1, lettere a), b), c) o d).</p>"], [null, "<p class=\"norm\">2.  Senza pregiudizio delle disposizioni del secondo comma, il decesso del cittadino dell'Unione non comporta la perdita del diritto di soggiorno dei familiari non aventi la cittadinanza di uno Stato membro e che hanno soggiornato nello Stato membro ospitante per almeno un anno prima del decesso del cittadino dell'Unione.</p>"], [null, "<p class=\"norm\">Prima dell'acquisizione del diritto di soggiorno permanente, il diritto di soggiorno delle persone interessate rimane subordinato al requisito che esse dimostrino di esercitare un'attività lavorativa subordinata od autonoma o di disporre per sé e per i familiari di risorse sufficienti affinché non divengano un onere per il sistema di assistenza sociale dello Stato membro ospitante durante il loro soggiorno, nonché di una assicurazione malattia che copra tutti i rischi nello Stato membro ospitante, ovvero di fare parte del nucleo familiare, già costituito nello Stato membro ospitante, di una persona che soddisfa tali condizioni. Le risorse sufficienti sono quelle indicate all'articolo 8, paragrafo 4.</p>"], [null, "<p class=\"norm\">I familiari in questione conservano il diritto di soggiorno esclusivamente a titolo personale.</p>"], [null, "<p class=\"norm\">3.  La partenza del cittadino dell'Unione dallo Stato membro ospitante o il suo decesso non comporta la perdita del diritto di soggiorno dei figli o del genitore che ne ha l'effettivo affidamento, indipendentemente dalla sua cittadinanza, se essi risiedono nello Stato membro ospitante e sono iscritti in un istituto scolastico per seguirvi gli studi, finché non terminano gli studi stessi.</p>"]]}, "13": {"label": "Articolo 13", "heading": "Mantenimento del diritto di soggiorno dei familiari in caso di divorzio, di annullamento del matrimonio o di scioglimento dell'unione registrata", "anchor": "art_13", "frags": [[null, "<p class=\"norm\">1.  Senza pregiudizio delle disposizioni del secondo comma, il divorzio, l'annullamento del matrimonio dei cittadini dell'Unione o lo scioglimento della loro unione registrata di cui all'articolo 2, punto 2, lettera b), non incidono sul diritto di soggiorno dei loro familiari aventi la cittadinanza di uno Stato membro.</p>"], [null, "<p class=\"norm\">Prima dell'acquisizione del diritto di soggiorno permanente, gli interessati devono soddisfare le condizioni previste all'articolo 7, paragrafo 1, lettere a), b), c) o d).</p>"], [null, "<p class=\"norm\">2.  Senza pregiudizio delle disposizioni del secondo comma, il divorzio, l'annullamento del matrimonio o lo scioglimento dell'unione registrata di cui all'articolo 2, punto 2, lettera b), non comportano la perdita del diritto di soggiorno dei familiari del cittadino dell'Unione non aventi la cittadinanza di uno Stato membro se:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>il matrimonio o l'unione registrata sono durati almeno tre anni, di cui almeno un anno nello Stato membro ospitante, prima dell'inizio del procedimento giudiziario di divorzio o annullamento o dello scioglimento dell'unione registrata di cui all'articolo 2, punto 2, lettera b); o</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>il coniuge o partner non avente la cittadinanza di uno Stato membro ha ottenuto l'affidamento dei figli del cittadino dell'Unione in base ad accordo tra i coniugi o i partner di cui all'articolo 2, punto 2, lettera b), o decisione giudiziaria; o</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>situazioni particolarmente difficili, come il fatto di aver subito violenza domestica durante il matrimonio o l'unione registrata, esigono la conservazione del diritto di soggiorno;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>il coniuge o il partner non avente la cittadinanza di uno Stato membro beneficia, in base ad un accordo tra i coniugi o conviventi di cui all'articolo 2, punto 2, lettera b), o decisione giudiziaria, di un diritto di visita al figlio minore, a condizione che l'organo giurisdizionale abbia ritenuto che le visite devono obbligatoriamente essere effettuate nello Stato membro ospitante, e fintantoché siano considerate necessarie.</p>\n</div>"], [null, "<p class=\"norm\">Prima dell'acquisizione del diritto di soggiorno permanente, il diritto di soggiorno delle persone interessate rimane subordinato al requisito che esse dimostrino di esercitare un'attività lavorativa subordinata o autonoma, o di disporre per sé e per i familiari di risorse sufficienti affinché non divengano un onere per il sistema di assistenza sociale dello Stato membro ospitante durante il soggiorno, nonché di una assicurazione malattia che copra tutti i rischi nello Stato membro ospitante, ovvero di fare parte del nucleo familiare, già costituito nello Stato membro ospitante, di una persona che soddisfa tali condizioni. Le risorse sufficienti sono quelle indicate all'articolo 8, paragrafo 4.</p>"], [null, "<p class=\"norm\">I familiari in questione conservano il diritto di soggiorno esclusivamente a titolo personale.</p>"]]}, "14": {"label": "Articolo 14", "heading": "Mantenimento del diritto di soggiorno", "anchor": "art_14", "frags": [[null, "<p class=\"norm\">1.  I cittadini dell'Unione e i loro familiari beneficiano del diritto di soggiorno di cui all'articolo 6 finché non diventano un onere eccessivo per il sistema di assistenza sociale dello Stato membro ospitante.</p>"], [null, "<p class=\"norm\">2.  I cittadini dell'Unione e i loro familiari beneficiano del diritto di soggiorno di cui agli articoli 7, 12 e 13 finché soddisfano le condizioni fissate negli stessi.</p>"], [null, "<p class=\"norm\">In casi specifici, qualora vi sia un dubbio ragionevole che il cittadino dell'Unione o i suoi familiari non soddisfano le condizioni stabilite negli articoli 7, 12 e 13, gli Stati membri possono effettuare una verifica in tal senso. Tale verifica non è effettuata sistematicamente.</p>"], [null, "<p class=\"norm\">3.  Il ricorso da parte di un cittadino dell'Unione o dei suoi familiari al sistema di assistenza sociale non dà luogo automaticamente ad un provvedimento di allontanamento.</p>"], [null, "<p class=\"norm\">4.  In deroga ai paragrafi 1 e 2 e senza pregiudizio delle disposizioni del capitolo VI, un provvedimento di allontanamento non può essere adottato nei confronti di cittadini dell'Unione o dei loro familiari qualora:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>i cittadini dell'Unione siano lavoratori subordinati o autonomi; oppure</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>i cittadini dell'Unione siano entrati nel territorio dello Stato membro ospitante per cercare un posto di lavoro. In tal caso i cittadini dell'Unione e i membri della loro famiglia non possono essere allontanati fino a quando i cittadini dell'Unione possono dimostrare di essere alla ricerca di un posto di lavoro e di avere buone possibilità di trovarlo.</p>\n</div>"]]}, "15": {"label": "Articolo 15", "heading": "Garanzie procedurali", "anchor": "art_15", "frags": [[null, "<p class=\"norm\">1.  Le procedure previste agli articoli 30 e 31 si applicano, mutatis mutandis, a tutti i provvedimenti che limitano la libera circolazione dei cittadini dell'Unione e dei loro familiari per motivi non attinenti all'ordine pubblico, alla pubblica sicurezza o alla sanità pubblica.</p>"], [null, "<p class=\"norm\">2.  Lo scadere della carta d'identità o del passaporto che ha consentito l'ingresso nello Stato membro ospitante e il rilascio dell'attestato d'iscrizione o della carta di soggiorno non giustifica l'allontanamento dal territorio.</p>"], [null, "<p class=\"norm\">3.  Lo Stato membro ospitante non può disporre, in aggiunta ai provvedimenti di allontanamento di cui al paragrafo 1, il divieto d'ingresso nel territorio nazionale.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "16": {"label": "Articolo 16", "heading": "Norma generale per i cittadini dell'Unione e i loro familiari", "anchor": "art_16", "frags": [[null, "<p class=\"norm\">1.  Il cittadino dell'Unione che abbia soggiornato legalmente ed in via continuativa per cinque anni nello Stato membro ospitante ha diritto al soggiorno permanente in detto Stato. Tale diritto non è subordinato alle condizioni di cui al capo III.</p>"], [null, "<p class=\"norm\">2.  Le disposizioni del paragrafo 1 si applicano anche ai familiari non aventi la cittadinanza di uno Stato membro che abbiano soggiornato legalmente in via continuativa per cinque anni assieme al cittadino dell'Unione nello Stato membro ospitante.</p>"], [null, "<p class=\"norm\">3.  La continuità della residenza non è pregiudicata da assenze temporanee che non superino complessivamente sei mesi all'anno né da assenze di durata superiore per l'assolvimento degli obblighi militari né da un'assenza di dodici mesi consecutivi al massimo dovuta a motivi rilevanti, quali gravidanza e maternità, malattia grave, studi o formazione professionale o il distacco per motivi di lavoro in un altro Stato membro o in un paese terzo.</p>"], [null, "<p class=\"norm\">4.  Una volta acquisito, il diritto di soggiorno permanente si perde soltanto a seguito di assenze dallo Stato membro ospitante di durata superiore a due anni consecutivi.</p>"]]}, "17": {"label": "Articolo 17", "heading": "Deroghe a favore dei lavoratori che hanno cessato la loro attività nello Stato membro ospitante e dei loro familiari", "anchor": "art_17", "frags": [[null, "<p class=\"norm\">1.  In deroga all'articolo 16, ha diritto di soggiorno permanente nello Stato membro ospitante prima della maturazione di un periodo continuativo di cinque anni di soggiorno:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>il lavoratore subordinato o autonomo il quale, nel momento in cui cessa l'attività, ha raggiunto l'età prevista dalla legislazione dello Stato membro ospitante ai fini dell'acquisizione del diritto alla pensione di vecchiaia, o il lavoratore subordinato il quale cessa di svolgere un'attività subordinata a seguito di pensionamento anticipato, a condizione che vi abbia svolto la propria attività almeno negli ultimi dodici mesi e vi abbia soggiornato in via continuativa per oltre tre anni.</p>\n</div>"], [null, "<p class=\"list\">Per talune categorie di lavoratori autonomi cui la legislazione dello Stato membro ospitante non riconosce il diritto alla pensione di vecchiaia la condizione relativa all'età è considerata soddisfatta quando il beneficiario ha raggiunto l'età di 60 anni;</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>il lavoratore subordinato o autonomo che ha soggiornato in modo continuativo nello Stato membro ospitante per oltre due anni e cessa di esercitare l'attività professionale a causa di una sopravvenuta incapacità lavorativa permanente.</p>\n</div>"], [null, "<p class=\"list\">Ove tale incapacità sia stata causata da un infortunio sul lavoro o da una malattia professionale che dà all'interessato diritto ad una prestazione interamente o parzialmente a carico di un'istituzione dello Stato membro ospitante, non si applica alcuna condizione relativa alla durata del soggiorno;</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>il lavoratore subordinato o autonomo il quale, dopo tre anni d'attività e di soggiorno continuativi nello Stato membro ospitante, eserciti un'attività subordinata o autonoma in un altro Stato membro, pur continuando a soggiornare nel territorio del primo Stato e facendovi ritorno in linea di principio ogni giorno o almeno una volta alla settimana.</p>\n</div>"], [null, "<p class=\"list\">Ai fini dell'acquisizione dei diritti previsti alle lettere a) e b), i periodi di occupazione trascorsi dall'interessato nello Stato membro in cui esercita un'attività sono considerati periodi trascorsi nello Stato membro ospitante.</p>"], [null, "<p class=\"norm\">I periodi di disoccupazione involontaria, debitamente comprovati dall'ufficio del lavoro competente, o i periodi di sospensione dell'attività indipendenti dalla volontà dell'interessato e l'assenza dal lavoro o la cessazione dell'attività per motivi di malattia o infortunio sono considerati periodi di occupazione.</p>"], [null, "<p class=\"norm\">2.  La sussistenza delle condizioni relative alla durata del soggiorno e dell'attività di cui al paragrafo 1, lettera a), e della condizione relativa alla durata del soggiorno di cui al paragrafo 1, lettera b), non è necessaria se il coniuge o il partner del lavoratore autonomo o subordinato, di cui all'articolo 2, punto 2, lettera b), è cittadino dello Stato membro ospitante o se ha perso la cittadinanza di tale Stato membro a seguito di matrimonio con il lavoratore autonomo o subordinato.</p>"], [null, "<p class=\"norm\">3.  I familiari, qualunque sia la loro cittadinanza, del lavoratore subordinato o autonomo, che soggiornano con quest'ultimo nel territorio dello Stato membro ospitante, godono del diritto di soggiorno permanente in detto Stato membro se il lavoratore stesso ha acquisito il diritto di soggiorno permanente nel territorio di detto Stato in forza del paragrafo 1.</p>"], [null, "<p class=\"norm\">4.  Se tuttavia il lavoratore subordinato o autonomo decede mentre era in attività senza aver ancora acquisito il diritto di soggiorno permanente nello Stato membro ospitante a norma del paragrafo 1, i familiari che soggiornano assieme al lavoratore nel territorio di detto Stato hanno il diritto di soggiorno permanente nello Stato stesso, a condizione che:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>il lavoratore subordinato o autonomo, alla data del suo decesso, avesse soggiornato in via continuativa nel territorio di questo Stato membro per due anni; o</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>il decesso sia avvenuto in seguito ad un infortunio sul lavoro o ad una malattia professionale; o</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>il coniuge superstite abbia perso la cittadinanza di tale Stato a seguito del suo matrimonio con il lavoratore subordinato o autonomo.</p>\n</div>"]]}, "18": {"label": "Articolo 18", "heading": "Acquisizione del diritto di soggiorno permanente da parte di taluni familiari non aventi la cittadinanza di uno Stato membro", "anchor": "art_18", "frags": [[null, "<p class=\"norm\">Senza pregiudizio dell'articolo 17, i familiari del cittadino dell'Unione di cui all'articolo 12, paragrafo 2, e all'articolo 13, paragrafo 2, che soddisfano le condizioni ivi previste, acquisiscono il diritto di soggiorno permanente dopo aver soggiornato legalmente e in via continuativa per cinque anni nello Stato membro ospitante.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "19": {"label": "Articolo 19", "heading": "Documento che attesta il soggiorno permanente per i cittadini dell'Unione", "anchor": "art_19", "frags": [[null, "<p class=\"norm\">1.  Gli Stati membri, dopo aver verificato la durata del soggiorno, su presentazione della domanda rilasciano al cittadino dell'Unione titolare del diritto di soggiorno permanente un documento che attesta tale soggiorno permanente.</p>"], [null, "<p class=\"norm\">2.  Il documento che attesta il soggiorno permanente è rilasciato nel più breve tempo possibile.</p>"]]}, "20": {"label": "Articolo 20", "heading": "Carta di soggiorno permanente per i familiari non aventi la cittadinanza di uno Stato membro", "anchor": "art_20", "frags": [[null, "<p class=\"norm\">1.  Gli Stati membri rilasciano ai familiari non aventi la cittadinanza di uno Stato membro e che sono titolari del diritto di soggiorno permanente, una carta di soggiorno permanente entro sei mesi dalla presentazione della domanda. La carta di soggiorno permanente è rinnovabile di diritto ogni dieci anni.</p>"], [null, "<p class=\"norm\">2.  La domanda di carta di soggiorno permanente è presentata prima dello scadere della carta di soggiorno. L'inadempimento dell'obbligo di richiedere la carta di soggiorno può rendere l'interessato passibile di sanzioni proporzionate e non discriminatorie.</p>"], [null, "<p class=\"norm\">3.  Le interruzioni di soggiorno che non superino, ogni volta, i due anni, non incidono sulla validità della carta di soggiorno permanente.</p>"]]}, "21": {"label": "Articolo 21", "heading": "Continuità del soggiorno", "anchor": "art_21", "frags": [[null, "<p class=\"norm\">La continuità del soggiorno, ai fini della presente direttiva, può essere comprovata con qualsiasi mezzo di prova ammesso dallo Stato membro ospitante. La continuità del soggiorno è interrotta da qualsiasi provvedimento di allontanamento validamente eseguito nei confronti della persona interessata.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "22": {"label": "Articolo 22", "heading": "Campo di applicazione territoriale", "anchor": "art_22", "frags": [[null, "<p class=\"norm\">Il diritto di soggiorno e il diritto di soggiorno permanente si estendono a tutto il territorio dello Stato membro ospitante. Limitazioni territoriali del diritto di soggiorno e del diritto di soggiorno permanente possono essere stabilite dagli Stati membri soltanto nei casi in cui siano previste anche per i propri cittadini.</p>"]]}, "23": {"label": "Articolo 23", "heading": "Diritti connessi", "anchor": "art_23", "frags": [[null, "<p class=\"norm\">I familiari del cittadino dell'Unione, qualunque sia la loro cittadinanza, titolari del diritto di soggiorno o del diritto di soggiorno permanente in uno Stato membro hanno diritto di esercitare un'attività economica come lavoratori subordinati o autonomi.</p>"]]}, "24": {"label": "Articolo 24", "heading": "Parità di trattamento", "anchor": "art_24", "frags": [[null, "<p class=\"norm\">1.  Fatte salve le disposizioni specifiche espressamente previste dal trattato e dal diritto derivato, ogni cittadino dell'Unione che risiede, in base alla presente direttiva, nel territorio dello Stato membro ospitante gode di pari trattamento rispetto ai cittadini di tale Stato nel campo di applicazione del trattato. Il beneficio di tale diritto si estende ai familiari non aventi la cittadinanza di uno Stato membro che siano titolari del diritto di soggiorno o del diritto di soggiorno permanente.</p>"], [null, "<p class=\"norm\">2.  In deroga al paragrafo 1, lo Stato membro ospitante non è tenuto ad attribuire il diritto a prestazioni d'assistenza sociale durante i primi tre mesi di soggiorno o, se del caso, durante il periodo più lungo previsto all'articolo 14, paragrafo 4, lettera b), né è tenuto a concedere prima dell'acquisizione del diritto di soggiorno permanente aiuti di mantenimento agli studi, compresa la formazione professionale, consistenti in borse di studio o prestiti per studenti, a persone che non siano lavoratori subordinati o autonomi, che non mantengano tale status o loro familiari.</p>"]]}, "25": {"label": "Articolo 25", "heading": "Disposizioni generali riguardanti i documenti di soggiorno", "anchor": "art_25", "frags": [[null, "<p class=\"norm\">1.  Il possesso di un attestato d'iscrizione di cui all'articolo 8, di un documento che certifichi il soggiorno permanente, della ricevuta della domanda di una carta di soggiorno di familiare di una carta di soggiorno o di una carta di soggiorno permanente, non può in nessun caso essere un prerequisito per l'esercizio di un diritto o il completamento di una formalità amministrativa, in quanto la qualità di beneficiario dei diritti può essere attestata con qualsiasi altro mezzo di prova.</p>"], [null, "<p class=\"norm\">2.  I documenti menzionati nel paragrafo 1 sono rilasciati a titolo gratuito o dietro versamento di una somma non eccedente quella richiesta ai cittadini nazionali per il rilascio di documenti analoghi.</p>"]]}, "26": {"label": "Articolo 26", "heading": "Controlli", "anchor": "art_26", "frags": [[null, "<p class=\"norm\">Gli Stati membri possono controllare l'osservanza di qualunque obbligo derivante dal diritto nazionale che imponga alle persone aventi una cittadinanza diversa di portare sempre con sé l'attestato d'iscrizione o la carta di soggiorno, a condizione che i propri cittadini siano soggetti allo stesso obbligo per quanto riguarda il possesso della carta d'identità. In caso d'inosservanza di tale obbligo, gli Stati membri possono applicare le stesse sanzioni che irrogano ai propri cittadini in caso di violazione dell'obbligo di portare con sé la carta d'identità.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "27": {"label": "Articolo 27", "heading": "Principi generali", "anchor": "art_27", "frags": [[null, "<p class=\"norm\">\n<span>\n<span class=\"boldface\">►C2</span>\n</span> 1.  Fatte salve le disposizioni del presente capo, gli Stati membri possono limitare la libertà di circolazione e di soggiorno di un cittadino dell'Unione o di un suo familiare,<span class=\"boldface\"> ◄ </span> qualunque sia la sua cittadinanza, per motivi di ordine pubblico, di pubblica sicurezza o di sanità pubblica. Tali motivi non possono essere invocati per fini economici.</p>"], [null, "<p class=\"norm\">2.  I provvedimenti adottati per motivi di ordine pubblico o di pubblica sicurezza rispettano il principio di proporzionalità e sono adottati esclusivamente in relazione al comportamento personale della persona nei riguardi della quale essi sono applicati. La sola esistenza di condanne penali non giustifica automaticamente l'adozione di tali provvedimenti.</p>"], [null, "<p class=\"norm\">Il comportamento personale deve rappresentare una minaccia reale, attuale e sufficientemente grave da pregiudicare un interesse fondamentale della società. Giustificazioni estranee al caso individuale o attinenti a ragioni di prevenzione generale non sono prese in considerazione.</p>"], [null, "<p class=\"norm\">3.  Al fine di verificare se l'interessato costituisce un pericolo per l'ordine pubblico o la pubblica sicurezza, in occasione del rilascio dell'attestato d'iscrizione o, in mancanza di un sistema di iscrizione, entro tre mesi dalla data di arrivo dell'interessato nel suo territorio o dal momento in cui ha dichiarato la sua presenza nel territorio in conformità dell'articolo 5, paragrafo 5, ovvero al momento del rilascio della carta di soggiorno, lo Stato membro ospitante può, qualora lo giudichi indispensabile, chiedere allo Stato membro di origine, ed eventualmente agli altri Stati membri, informazioni sui precedenti penali del cittadino dell'Unione o di un suo familiare. Tale consultazione non può avere carattere sistematico. Lo Stato membro consultato fa pervenire la propria risposta entro un termine di due mesi.</p>"], [null, "<p class=\"norm\">4.  Lo Stato membro che ha rilasciato il passaporto o la carta di identità riammette senza formalità nel suo territorio il titolare di tale documento che è stato allontanato per motivi di ordine pubblico, di pubblica sicurezza o di salute pubblica da un altro Stato membro, quand'anche il documento in questione sia scaduto o sia contestata la cittadinanza del titolare.</p>"]]}, "28": {"label": "Articolo 28", "heading": "Protezione contro l'allontanamento", "anchor": "art_28", "frags": [[null, "<p class=\"norm\">1.  Prima di adottare un provvedimento di allontanamento dal territorio per motivi di ordine pubblico o di pubblica sicurezza, lo Stato membro ospitante tiene conto di elementi quali la durata del soggiorno dell'interessato nel suo territorio, la sua età, il suo stato di salute, la sua situazione familiare e economica, la sua integrazione sociale e culturale nello Stato membro ospitante e importanza dei suoi legami con il paese d'origine.</p>"], [null, "<p class=\"norm\">2.  Lo Stato membro ospitante non può adottare provvedimenti di allontanamento dal territorio nei confronti del cittadino dell'Unione o del suo familiare, qualunque sia la sua cittadinanza, che abbia acquisito il diritto di soggiorno permanente nel suo territorio se non per gravi motivi di ordine pubblico o di pubblica sicurezza.</p>"], [null, "<p class=\"norm\">3.  Il cittadino dell'Unione non può essere oggetto di una decisione di allontanamento, salvo se la decisione è adottata per motivi imperativi di pubblica sicurezza definiti dallo Stato membro, qualora:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>abbia soggiornato nello Stato membro ospitante i precedenti dieci anni; o</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>sia minorenne, salvo qualora l'allontanamento sia necessario nell'interesse del bambino, secondo quanto contemplato dalla convenzione delle Nazioni Unite sui diritti del fanciullo del 20 novembre 1989.</p>\n</div>"]]}, "29": {"label": "Articolo 29", "heading": "Sanità pubblica", "anchor": "art_29", "frags": [[null, "<p class=\"norm\">1.  Le sole malattie che possono giustificare misure restrittive della libertà di circolazione sono quelle con potenziale epidemico, quali definite dai pertinenti strumenti dell'Organizzazione mondiale della sanità, nonché altre malattie infettive o parassitarie contagiose, sempreché esse siano oggetto di disposizioni di protezione che si applicano ai cittadini dello Stato membro ospitante.</p>"], [null, "<p class=\"norm\">2.  L'insorgere di malattie posteriormente ad un periodo di tre mesi successivi alla data di arrivo non può giustificare l'allontanamento dal territorio.</p>"], [null, "<p class=\"norm\">3.  Ove sussistano seri indizi che ciò è necessario, lo Stato membro può sottoporre i titolari del diritto di soggiorno, entro tre mesi dalla data di arrivo, a visita medica gratuita al fine di accertare che non soffrano di patologie indicate al paragrafo 1. Tali visite mediche non possono avere carattere sistematico.</p>"]]}, "30": {"label": "Articolo 30", "heading": "Notificazione dei provvedimenti", "anchor": "art_30", "frags": [[null, "<p class=\"norm\">1.  Ogni provvedimento adottato a norma dell'articolo 27, paragrafo 1, è notificato per iscritto all'interessato secondo modalità che consentano a questi di comprenderne il contenuto e le conseguenze.</p>"], [null, "<p class=\"norm\">2.  I motivi circostanziati e completi di ordine pubblico, di pubblica sicurezza o di sanità pubblica che giustificano l'adozione del provvedimento nei suoi confronti sono comunicati all'interessato, salvo che vi ostino motivi attinenti alla sicurezza dello Stato.</p>"], [null, "<p class=\"norm\">3.  La notifica riporta l'indicazione dell'organo giurisdizionale o dell'autorità amministrativa dinanzi al quale l'interessato può opporre ricorso e il termine entro il quale deve agire e, all'occorrenza, l'indicazione del termine impartito per lasciare il territorio dello Stato membro. Fatti salvi i casi di urgenza debitamente comprovata, tale termine non può essere inferiore a un mese a decorrere dalla data di notificazione.</p>"]]}, "31": {"label": "Articolo 31", "heading": "Garanzie procedurali", "anchor": "art_31", "frags": [[null, "<p class=\"norm\">1.  L'interessato può accedere ai mezzi di impugnazione giurisdizionali e, all'occorrenza, amministrativi nello Stato membro ospitante, al fine di presentare ricorso o chiedere la revisione di ogni provvedimento adottato nei suoi confronti per motivi di ordine pubblico, pubblica sicurezza o sanità pubblica.</p>"], [null, "<p class=\"norm\">2.  Laddove l'impugnazione o la richiesta di revisione del provvedimento di allontanamento sia accompagnata da una richiesta di ordinanza provvisoria di sospensione dell'esecuzione di detto provvedimento, l'effettivo allontanamento dal territorio non può avere luogo fintantoché non è stata adottata una decisione sull'ordinanza provvisoria, salvo qualora:</p>"], [null, "<div style=\"margin-left: 12pt; text-indent: -12pt; \">\n<p class=\"norm\">—<span style=\"word-spacing: 0\"> </span>il provvedimento di allontanamento si basi su una precedente decisione giudiziale, o</p>\n</div>"], [null, "<div style=\"margin-left: 12pt; text-indent: -12pt; \">\n<p class=\"norm\">—<span style=\"word-spacing: 0\"> </span>le persone interessate abbiano precedentemente fruito di una revisione, o</p>\n</div>"], [null, "<div style=\"margin-left: 12pt; text-indent: -12pt; \">\n<p class=\"norm\">—<span style=\"word-spacing: 0\"> </span>il provvedimento sia fondato su motivi imperativi di pubblica sicurezza di cui all'articolo 28, paragrafo 3.</p>\n</div>"], [null, "<p class=\"norm\">3.  I mezzi di impugnazione comprendono l'esame della legittimità del provvedimento nonché dei fatti e delle circostanze che ne giustificano l'adozione. Essi garantiscono che il provvedimento non sia sproporzionato, in particolare rispetto ai requisiti posti dall'articolo 28.</p>"], [null, "<p class=\"norm\">4.  Gli Stati membri possono vietare la presenza dell'interessato nel loro territorio per tutta la durata della procedura di ricorso, ma non possono vietare che presenti di persona la sua difesa, tranne qualora la sua presenza possa provocare gravi turbative dell'ordine pubblico o della pubblica sicurezza o quando il ricorso o la revisione riguardano il divieto d'ingresso nel territorio.</p>"]]}, "32": {"label": "Articolo 32", "heading": "Effetti nel tempo del divieto di ingresso nel territorio", "anchor": "art_32", "frags": [[null, "<p class=\"norm\">1.  La persona nei cui confronti sia stato adottato un provvedimento di divieto d'ingresso nel territorio per motivi d'ordine pubblico o pubblica sicurezza può presentare una domanda di revoca del divieto d'ingresso nel territorio nazionale dopo il decorso di un congruo periodo, determinato in funzione delle circostanze e in ogni modo dopo tre anni a decorrere dall'esecuzione del provvedimento definitivo di divieto validamente adottato ai sensi del diritto comunitario, nella quale essa deve addurre argomenti intesi a dimostrare l'avvenuto oggettivo mutamento delle circostanze che hanno motivato la decisione di vietarne l'ingresso nel territorio.</p>"], [null, "<p class=\"norm\">Lo Stato membro interessato si pronuncia in merito a tale nuova domanda entro sei mesi dalla data di presentazione della stessa.</p>"], [null, "<p class=\"norm\">2.  La persona di cui al paragrafo 1 non ha diritto d'ingresso nel territorio dello Stato membro interessato durante l'esame della sua domanda.</p>"]]}, "33": {"label": "Articolo 33", "heading": "Allontanamento a titolo di pena o misura accessoria", "anchor": "art_33", "frags": [[null, "<p class=\"norm\">1.  Lo Stato membro ospitante può validamente adottare un provvedimento di allontanamento dal territorio a titolo di pena o di misura accessoria ad una pena detentiva soltanto nel rispetto dei requisiti di cui agli articoli 27, 28 e 29.</p>"], [null, "<p class=\"norm\">2.  Se il provvedimento di allontanamento di cui al paragrafo 1 è eseguito a oltre due anni di distanza dalla sua adozione, lo Stato membro verifica che la minaccia che l'interessato costituisce per l'ordine pubblico o per la pubblica sicurezza sia attuale e reale, e valuta l'eventuale mutamento obiettivo delle circostanze intervenuto successivamente all'adozione del provvedimento di allontanamento.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "34": {"label": "Articolo 34", "heading": "Pubblicità", "anchor": "art_34", "frags": [[null, "<p class=\"norm\">Gli Stati membri diffondono le informazioni relative ai diritti e agli obblighi dei cittadini dell'Unione e dei loro familiari nel settore disciplinato dalla presente direttiva, in particolare mediante campagne di sensibilizzazione effettuate tramite i media e altri mezzi di comunicazione nazionali e locali.</p>"]]}, "35": {"label": "Articolo 35", "heading": "Abuso di diritto", "anchor": "art_35", "frags": [[null, "<p class=\"norm\">Gli Stati membri possono adottare le misure necessarie per rifiutare, estinguere o revocare un diritto conferito dalla presente direttiva, in caso di abuso di diritto o frode, quale ad esempio un matrimonio fittizio. Qualsiasi misura di questo tipo è proporzionata ed è soggetta alle garanzie procedurali previste agli articoli 30 e 31.</p>"]]}, "36": {"label": "Articolo 36", "heading": "Sanzioni", "anchor": "art_36", "frags": [[null, "<p class=\"norm\">Gli Stati membri determinano le sanzioni da irrogare in caso di violazione delle norme nazionali adottate in attuazione della presente direttiva e adottano tutti i provvedimenti necessari per la loro applicazione. Le sanzioni previste sono effettive e proporzionate. Gli Stati membri notificano alla Commissione tali disposizioni entro il 30 aprile 2006 e provvedono a comunicare immediatamente le eventuali successive modifiche.</p>"]]}, "37": {"label": "Articolo 37", "heading": "Disposizioni nazionali più favorevoli", "anchor": "art_37", "frags": [[null, "<p class=\"norm\">Le disposizioni della presente direttiva non pregiudicano le disposizioni legislative, regolamentari e amministrative di diritto interno che siano più favorevoli ai beneficiari della presente direttiva.</p>"]]}, "38": {"label": "Articolo 38", "heading": "Abrogazione", "anchor": "art_38", "frags": [[null, "<p class=\"modref\">\n▼M1 —————</p>"], [null, "<p class=\"modref\">\n▼C1\n</p>"], [null, "<p class=\"norm\">2.  Le direttive 64/221/CEE, 68/360/CEE, 72/194/CEE, 73/148/CEE, 75/34/CEE, 75/35/CEE, 90/364/CEE, 90/365/CEE e 93/96/CEE sono abrogate con effetto dal 30 aprile 2006.</p>"], [null, "<p class=\"norm\">3.  I riferimenti fatti agli articoli e alle direttive abrogati si intendono fatti alla presente direttiva.</p>"]]}, "39": {"label": "Articolo 39", "heading": "Relazione", "anchor": "art_39", "frags": [[null, "<p class=\"norm\">Entro il 30 aprile 2008 la Commissione presenta al Parlamento europeo ed al Consiglio una relazione sull'applicazione della presente direttiva corredata, all'occorrenza, di opportune proposte, in particolare sull'opportunità di prorogare il periodo nel quale il cittadino dell'Unione e i suoi familiari possono soggiornare senza condizioni nel territorio dello Stato membro ospitante. Gli Stati membri trasmettono alla Commissione tutte le informazioni utili ai fini della relazione.</p>"]]}, "40": {"label": "Articolo 40", "heading": "Recepimento", "anchor": "art_40", "frags": [[null, "<p class=\"norm\">1.  Gli Stati membri adottano e pubblicano entro il 30 aprile 2006 le disposizioni legislative, regolamentari ed amministrative necessarie per conformarsi alla presente direttiva.</p>"], [null, "<p class=\"norm\">Quando gli Stati membri adottano tali disposizioni, queste contengono un riferimento alla presente direttiva o sono corredate di un siffatto riferimento all'atto della pubblicazione ufficiale. Le modalità di tale riferimento sono decise dagli Stati membri.</p>"], [null, "<p class=\"norm\">2.  Gli Stati membri comunicano alla Commissione il testo delle disposizioni di diritto interno che essi adottano nel settore disciplinato dalla presente direttiva nonché della tabella di concordanza tra tali disposizioni e la presente direttiva.</p>"]]}, "41": {"label": "Articolo 41", "heading": "Entrata in vigore", "anchor": "art_41", "frags": [[null, "<p class=\"norm\">La presente direttiva entra in vigore il giorno della pubblicazione nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea</span>.</p>"]]}, "42": {"label": "Articolo 42", "heading": "Destinatari", "anchor": "art_42", "frags": [[null, "<p class=\"norm\">Gli Stati membri sono destinatari della presente direttiva.</p>"]]}}, "recitals": {}};